# -*- coding: utf-8 -*-
from fpdf import FPDF
from PIL import Image
FD="/usr/share/fonts/truetype/dejavu"
NAVY=(20,35,63); INK=(33,37,43); GREY=(95,102,112); SOFT=(238,241,247); LINE=(214,219,228); WHITE=(255,255,255); ACCENT=(176,141,87)
class M(FPDF):
    def __init__(self):
        super().__init__("P","mm","A4"); self.set_auto_page_break(True,16)
        self.add_font("S","",f"{FD}/DejaVuSans.ttf"); self.add_font("S","B",f"{FD}/DejaVuSans-Bold.ttf")
        self.add_font("R","",f"{FD}/DejaVuSerif.ttf"); self.add_font("R","B",f"{FD}/DejaVuSerif-Bold.ttf")
        self.set_margins(20,20,20); self.cw=170
    def header(self):
        if self.page_no()==1: return
        self.set_y(8); self.set_font("R","B",9); self.set_text_color(*NAVY); self.cell(0,5,"STRIKER",align="L")
        self.set_font("S","",7.5); self.set_text_color(*GREY); self.set_xy(20,8); self.cell(self.cw,5,"Краткий инвестиционный меморандум",align="R")
        self.set_draw_color(*LINE); self.set_line_width(0.2); self.line(20,15,190,15); self.set_y(20)
    def footer(self):
        self.set_y(-13); self.set_draw_color(*LINE); self.set_line_width(0.2); self.line(20,self.get_y(),190,self.get_y())
        self.set_y(-11); self.set_font("S","",7); self.set_text_color(*GREY)
        self.cell(self.cw-20,5,"Строго конфиденциально · STRIKER · для предварительного обсуждения",align="L"); self.cell(20,5,f"{self.page_no()}",align="R")
    def section(self,num,title):
        self.add_page(); y=self.get_y()
        self.set_fill_color(*NAVY); self.rect(20,y+0.4,6.8,6.8,"F")
        self.set_font("S","B",9.5); self.set_text_color(*WHITE); self.set_xy(20,y+1.6); self.cell(6.8,4.6,num,align="C")
        self.set_font("R","B",13.5); self.set_text_color(*NAVY); self.set_xy(29.2,y+0.4); self.cell(0,7,title)
        self.ln(10); self.set_draw_color(*NAVY); self.set_line_width(0.4); self.line(20,self.get_y(),190,self.get_y()); self.ln(3)
    def body(self,txt,size=9.5,after=2.4):
        self.set_font("S","",size); self.set_text_color(*INK); self.multi_cell(self.cw,4.8,txt,align="J"); self.ln(after)
    def bullet(self,lead,txt,size=9.5):
        t=("**"+lead.strip()+"** " if lead else "")+txt
        self.set_font("S","",size)
        n=len(self.multi_cell(self.cw-6,4.8,t,dry_run=True,output="LINES",markdown=True))
        if self.get_y()+n*4.8+2.4>277: self.add_page()
        y=self.get_y(); self.set_font("S","B",9.5); self.set_text_color(*ACCENT); self.set_xy(20,y); self.cell(6,4.8,"—")
        self.set_text_color(*INK); self.set_xy(26,y); self.multi_cell(self.cw-6,4.8,t,align="J",markdown=True); self.ln(1.8)
    def img(self,path,w=160,cap=None):
        iw,ih=Image.open(path).size; h=w*ih/iw
        if self.get_y()+h+(7 if cap else 0)>278: self.add_page()
        x=20+(self.cw-w)/2; self.image(path,x=x,y=self.get_y(),w=w); self.set_y(self.get_y()+h+1.8)
        if cap:
            self.set_font("S","",7.8); self.set_text_color(*GREY); self.multi_cell(self.cw,3.8,cap,align="C"); self.ln(1.5)
    def kvtable(self,rows,kw=54):
        self.set_draw_color(*LINE); vw=self.cw-kw
        for k,v in rows:
            self.set_font("S","",8.9); n=len(self.multi_cell(vw-4,4.4,v,dry_run=True,output="LINES")); rh=max(7.2,4.4*n+3)
            if self.get_y()+rh>276: self.add_page()
            y=self.get_y(); self.set_fill_color(*SOFT); self.rect(20,y,kw,rh,"F")
            self.set_draw_color(*LINE); self.set_line_width(0.2); self.rect(20,y,kw,rh); self.rect(20+kw,y,vw,rh)
            self.set_font("S","B",8.9); self.set_text_color(*NAVY); self.set_xy(22,y+1.9); self.multi_cell(kw-3,4.4,k)
            self.set_font("S","",8.9); self.set_text_color(*INK); self.set_xy(22+kw,y+1.9); self.multi_cell(vw-4,4.4,v); self.set_y(y+rh)
    def table(self,headers,rows,widths):
        self.set_font("S","B",8.4); hh=7; y=self.get_y(); self.set_fill_color(*NAVY); self.rect(20,y,self.cw,hh,"F")
        self.set_text_color(*WHITE); cx=20
        for w,h in zip(widths,headers): self.set_xy(cx+1.5,y+1.6); self.cell(w-2,4,h); cx+=w
        self.set_y(y+hh)
        for i,row in enumerate(rows):
            self.set_font("S","",8.3); n=max(len(self.multi_cell(widths[j]-3,4.0,c,dry_run=True,output="LINES")) for j,c in enumerate(row))
            rh=max(6.4,4.0*n+2.6); yy=self.get_y()
            if i%2==1: self.set_fill_color(248,249,252); self.rect(20,yy,self.cw,rh,"F")
            self.set_draw_color(*LINE); self.set_line_width(0.2); self.rect(20,yy,self.cw,rh)
            cx=20
            for j,c in enumerate(row):
                self.set_font("S","B",8.3) if j==0 else self.set_font("S","",8.3)
                self.set_text_color(*(NAVY if j==0 else INK)); self.set_xy(cx+1.5,yy+1.4); self.multi_cell(widths[j]-3,4.0,c); cx+=widths[j]
            self.set_y(yy+rh)

p=M(); p.add_page()
# COVER
p.set_fill_color(*NAVY); p.rect(0,0,210,54,"F")
p.set_y(13); p.set_font("R","B",30); p.set_text_color(*WHITE); p.cell(0,12,"STRIKER",align="C")
p.set_font("S","",10); p.set_text_color(214,221,233); p.set_y(27); p.cell(0,5,"Проект F/A-259U · лёгкий многоцелевой боевой и учебно-боевой самолёт",align="C")
p.set_draw_color(*ACCENT); p.set_line_width(0.6); p.line(86,38,124,38)
p.set_font("S","B",10.5); p.set_text_color(*WHITE); p.set_y(41); p.cell(0,5,"КРАТКИЙ ИНВЕСТИЦИОННЫЙ МЕМОРАНДУМ",align="C")
p.set_y(62); p.set_font("S","",8.2); p.set_text_color(*GREY); p.cell(0,4,"СТРОГО КОНФИДЕНЦИАЛЬНО · ДЛЯ ПРЕДВАРИТЕЛЬНОГО ОБСУЖДЕНИЯ · 2026",align="C")
p.ln(10)
p.set_font("S","",9.5); p.set_text_color(*INK)
p.multi_cell(p.cw,4.9,"Проект STRIKER — серийное производство и поставка современного лёгкого боевого и учебно-боевого самолёта F/A-259U на проверенной сертифицированной платформе чешского производителя Aero Vodochody, оснащённого новым крылом, современной авионикой и двигателем. Производство — на территории НАТО и ЕС. Настоящий документ кратко излагает проект, экономику и рекомендованную корпоративно-налоговую структуру с готовыми решениями и аргументами в их пользу. Детальный разбор альтернатив и условия сделки вынесены в отдельные документы (полный меморандум и term sheet).",align="J")
p.ln(3)
p.set_draw_color(*ACCENT); p.set_line_width(0.5); p.line(20,p.get_y(),190,p.get_y()); p.ln(5)
p.set_font("S","B",9.5); p.set_text_color(*NAVY); p.cell(0,5,"Ключевые параметры проекта"); p.ln(8)
p.kvtable([("Стоимость проекта","≈ 420 млн USD (3 года: 150 / 170 / 100)"),
 ("Цена / прибыль на самолёт","25 млн USD / не менее 3 млн USD"),
 ("Серийный выпуск","до 48 в год, всего не менее 300 машин"),
 ("Совокупная прибыль","не менее 900 млн USD"),
 ("Окупаемость","около 8-го года с начала финансирования"),
 ("Стартовый портфель","предварительные контракты (LOI) на 200 самолётов")],kw=54)

p.section("1","Инвестиционная теза")
p.body("Цель проекта — создать серийное производство современного лёгкого боевого самолёта и вывести его на мировой рынок. Спрос на лёгкие боевые и учебно-боевые машины устойчиво растёт: государства обновляют устаревшие парки и ищут доступную альтернативу тяжёлым истребителям — с близкими боевыми возможностями, но кратно меньшей стоимостью приобретения и эксплуатации.")
p.bullet("Подтверждение рыночного спроса. ","На международном авиасалоне в Ле-Бурже (Paris Air Show) заключены предварительные («мягкие») контракты — соглашения о намерениях (Letters of Intent) — на поставку 200 самолётов данной конфигурации. Эти договорённости подтверждают устойчивый рыночный интерес к машине данного класса и формируют стартовый портфель заказов проекта. Предварительные контракты подлежат переводу в твёрдые поставочные договоры на этапе оформления структуры и привлечения финансирования.")
p.bullet("Доступная многоцелевая платформа. ","Непосредственная авиационная поддержка, воздушный бой, разведка, радиоэлектронная борьба и продвинутая подготовка лётчиков — в одном самолёте.")
p.bullet("Производство и поставки из стран НАТО и ЕС. ","Интеграция в оборонное сотрудничество в рамках этих объединений; опора на готовый производственный опыт и проверенных мировых поставщиков.")
p.bullet("Умеренные капитальные вложения. ","Относительно тяжёлых платформ — при высокой совокупной прибыли и приемлемом сроке окупаемости.")
p.bullet("Консервативная модель. ","Расчёты выполнены осторожно: заложены максимально возможные издержки и минимальная прибыль; доходы от планового ремонта и обслуживания поставленного парка в модель не включены.")

p.section("2","Продукт: F/A-259U STRIKER")
p.body("F/A-259U «STRIKER» — лёгкий многоцелевой ударный и учебно-боевой самолёт на проверенной сертифицированной платформе Aero Vodochody с новым крылом, современной авионикой и двигателем. Состав бортового оборудования позволяет выполнять широкий круг боевых задач и одновременно служить платформой для продвинутой подготовки лётчиков.")
p.bullet("Боевые возможности. ","Непосредственная авиаподдержка (CAS), воздушный бой и противовоздушные операции, разведка и целеуказание (ISR), радиоэлектронная борьба, продвинутая и переходная подготовка лётчиков (LIFT), совместимая с подготовкой на F-16 и F-35.")
p.bullet("Ключевые особенности. ","Радар с активной фазированной антенной решёткой; авионика открытой архитектуры с передачей данных в реальном времени (Link 16); семь точек подвески и широкая номенклатура вооружения; высокая живучесть (бронирование кабины, катапультное кресло, эксплуатация с неподготовленных полос); экономичная эксплуатация и обслуживание.")
p.ln(1); p.set_font("S","B",9.5); p.set_text_color(*NAVY); p.cell(0,5,"Основные характеристики"); p.ln(7)
p.kvtable([("Размах крыла / длина","9,54 м / 12,72 м"),("Макс. взлётная масса","8 300 кг"),("Полезная нагрузка","до 3 000 кг"),
 ("Макс. скорость (у земли)","936 км/ч"),("Практический потолок","13 200 м"),("Боевые перегрузки","+8 / −4 g"),("Двигатель","АI-322F с форсажем, FADEC")],kw=54)

p.section("3","Экономика проекта")
p.bullet("Стоимость проекта — ","около 420 млн USD; вкладывается поэтапно: 1-й год 150 млн, 2-й — 170 млн, 3-й — 100 млн.")
p.bullet("Цена самолёта — ","25 млн USD; себестоимость — до 20 млн; чистая прибыль — не менее 3 млн USD на самолёт.")
p.bullet("Серийный выпуск — ","до 48 самолётов в год, всего не менее 300 машин; совокупная чистая прибыль проекта — не менее 900 млн USD.")
p.ln(1)
p.table(["Сценарий","Окупаемость","Совокупная прибыль","Ключевые условия"],
 [["Базовый","около 8-го года","не менее 900 млн $","цена 25 млн $, прибыль 3 млн $/шт, выход на 48 шт/год по графику"],
  ["Консервативный","около 10-го года","порядка 700 млн $","издержки выше, прибыль ~2 млн $/шт, медленнее выход на мощность"]],
 widths=[28,28,34,80])
p.ln(2)
p.img("assets_cashflow.png",w=150,cap="Накопленный денежный поток, базовый сценарий (млн USD). Точка окупаемости — между 7-м и 8-м годами.")
p.set_font("S","B",9.5); p.set_text_color(*NAVY); p.cell(0,5,"Ориентир условий для инвестора"); p.ln(7)
p.body("Объём привлечения — около 420 млн USD (полное финансирование трёх лет разработки, испытаний и запуска серийного производства). Ориентировочная оценка проекта (post-money) — порядка 0,7–1,1 млрд USD; совокупная доля инвесторов — ориентировочно 40–60%. Величины индикативны и уточняются по итогам переговоров и подтверждённой финансовой модели; детальные условия — в term sheet.")

p.section("4","Этапы и сроки реализации")
p.body("От начала финансирования до старта серийного производства — 37 месяцев. Ключевые вехи: до 14 месяцев — новый двигатель и крыло, пакет рабочей конструкторской документации, макетный образец и первый опытный самолёт; до 22 месяцев — опытные образцы для испытаний крыла, оборудования и вооружения; до 32–36 месяцев — все виды испытаний и передача предсерийного самолёта заказчику на войсковые испытания; 37-й месяц — начало серийного производства.")
p.img("assets_gantt.png",w=162,cap="Календарный план от начала финансирования (месяцы).")

p.section("5","Рекомендованная структура и готовые решения")
p.body("Структура состоит из трёх уровней. Инвесторы и участники проекта владеют единой холдинговой компанией; та напрямую владеет двумя болгарскими компаниями — производственной (PrincipalCo) и продающей (SalesCo). Холдинг держит права на разработку и распределяет прибыль инвесторам. На первом этапе сборку выполняет независимый чешский завод Aero Vodochody по заказу группы; по мере роста группа переходит к собственному производству на базе PrincipalCo.")
p.img("struct_stage1.png",w=158,cap="Этап 1 — производство по заказу: сборку ведёт независимый завод Aero Vodochody (Чехия) по заказу и за плату.")
p.kvtable([("Холдинг","Великобритания — владеет проектом и правами, финансирует, распределяет прибыль инвесторам"),
 ("Производственная компания","Болгария (PrincipalCo) — OEM: IP-права, держатель DOA и сертификата типа, управление производством"),
 ("Продающая компания","Болгария (SalesCo) — военно-экспортная лицензия, контракты с покупателями, продажа"),
 ("Сборка","Этап 1 — Aero Vodochody (Чехия) по заказу; Этап 2 — собственный завод (Болгария или Польша)"),
 ("Права на разработку","у операционной компании (Модель 1) — прибыль облагается в Болгарии, роялти не возникает"),
 ("Налог","Болгария 10% — одна из самых низких в ЕС; передача наверх и инвестору — 0% удержания")],kw=54)
p.body("Этап 2 — собственное производство. По мере роста объёмов PrincipalCo переходит от сборки по заказу к собственному заводу. Переход не требует перестройки структуры владения: холдинг и обе операционные компании сохраняются, меняется лишь фактическое производственное звено.")
p.img("struct_stage2.png",w=158,cap="Этап 2 — собственное производство: сборка переносится на собственные мощности PrincipalCo.")

p.section("6","Ключевые преимущества")
p.bullet("Низкая нагрузка на прибыль. ","Операционная прибыль облагается в Болгарии по плоской ставке 10% — одной из самых низких в ЕС; к этому добавляются дешёвая рабочая сила в ЕС, невысокая стоимость организации производства и логистическая близость к поставщикам и рынкам региона.")
p.bullet("Прибыль доходит наверх без потерь. ","Передача из Болгарии в британский холдинг не облагается налогом у источника; полученные холдингом дивиденды в Великобритании освобождены.")
p.bullet("Эффективное распределение. ","Великобритания не удерживает налог на дивиденды ни при каком составе собственников — до инвестора доходит около 9/10 чистой прибыли.")
p.bullet("Надёжная юрисдикция холдинга. ","Английское право, независимые суды и развитый арбитраж — удобно для соинвестирования, финансирования и выхода.")
p.bullet("Соответствие военно-экспортным требованиям. ","Болгария и Чехия — члены НАТО и ЕС с полноценными режимами лицензирования; производственная сертификация на PrincipalCo, экспортная лицензия на SalesCo.")
p.bullet("Защита инвестиций. ","Британский холдинг пользуется действующими договорами о защите инвестиций с Болгарией и Чехией: гарантии от экспроприации, свободный перевод доходов и прямой доступ к международному арбитражу против государства.")
p.bullet("Гибкость и удобный выход. ","Переход к собственному производству не требует перестройки владения; выход — продажа или IPO на уровне холдинга, прирост на уровне структуры освобождён от налога.")

p.section("7","Налоговый результат")
p.body("Прибыль облагается налогом один раз — на уровне Болгарии по ставке 10%. При передаче вверх в холдинг и далее инвесторам налога у источника не возникает; из каждого миллиона операционной прибыли до инвесторов доходит около 900 тысяч.")
p.table(["Шаг движения прибыли","Налог","Комментарий"],
 [["Прибыль операционной компании (Болгария)","10%","одна из самых низких ставок в ЕС"],
  ["Передача из Болгарии в холдинг","0%","по налоговому соглашению (доля ≥10%, не менее года)"],
  ["Выплата дивидендов инвесторам","0%","Великобритания не удерживает налог ни при каком составе собственников"],
  ["Продажа долей при выходе","0%*","*на уровне структуры; налог инвестора — в стране его резидентства"]],
 widths=[64,16,90])
p.ln(2)
p.img("assets_flow.png",w=168,cap="Путь 1 млн € операционной прибыли: 10% болгарский налог — и далее без потерь до инвестора.")

p.section("8","Допуск иностранных собственников к оборонному активу")
p.body("Прямого запрета на участие иностранных, в том числе ближневосточных, инвесторов в оборонных авиапроектах НАТО и ЕС нет. Практика это подтверждает: суверенный фонд Абу-Даби Mubadala несколько лет владел итальянским Piaggio Aerospace; EDGE (ОАЭ) приобрёл контроль в эстонской Milrem Robotics с правовым ограждением чувствительных технологий НАТО и ЕС. Вопрос не в запрете, а в условиях допуска — их задаёт проверка иностранных инвестиций (в ЕС — Регламент 2019/452), затрагивающая прежде всего Болгарию.")
p.body("Согласование иностранного владения — плановый этап запуска. Применяется отработанная в оборонной практике схема разделения экономического участия и контроля: на уровне холдинга — классы акций (экономика — всем инвесторам, голосующий контроль и право вето — лицам из стран НАТО и ЕС); на уровне болгарских компаний — совет директоров и ключевые управленцы с допуском к гостайне и соглашение о безопасности.")
p.img("assets_control.png",w=160,cap="Прибыль получают все инвесторы; контроль — голос и вето в холдинге и управление в болгарских компаниях — за лицами из стран НАТО и ЕС.")

p.section("9","Условия реализации и границы")
p.body("Налоговые и структурные выводы действуют при реальном присутствии (управление, персонал, офис по месту регистрации) и наличии у каждого элемента структуры самостоятельной деловой цели. Финансовые показатели отражают оценку организаторов проекта и подлежат подтверждению инвестором. Принципиальная допустимость структуры обоснована прецедентами; конкретные условия допуска к оборонному активу прорабатываются с болгарским регулятором на старте проекта. Детальные коммерческие условия сделки (оценка, доли, транши, преференции, порядок выхода) изложены в отдельном документе об условиях сделки (term sheet).")
p.ln(2); p.set_font("S","",7.9); p.set_text_color(*GREY)
p.multi_cell(p.cw,3.9,"Настоящий документ носит ознакомительный характер, не является офертой, налоговой или юридической консультацией. Ставки и правовые выводы приведены по состоянию на 2026 год и подлежат подтверждению местными консультантами при внедрении структуры.",align="J")

